files.content:
*{
    margin:0;
    padding:0;
    box-sizing:border-box;
    font-family:'Segoe UI',sans-serif;
}

body{
    background:#f4f4f4;
}

.layout{
    display:flex;
    min-height:100vh;
}

/* SIDEBAR */

.sidebar{
    width:220px;
    background:#fff;
    padding:20px;
}

.sidebar h2{
    margin-bottom:20px;
}

.sidebar ul{
    list-style:none;
}

.sidebar li{
    padding:14px;
    margin-bottom:8px;
    display:flex;
    align-items:center;
    gap:12px;
}

.sidebar .active{
    background:#e91e63;
    color:#fff;
}

.sidebar img{
    width:24px;
    height:24px;
}

/* CONTENT */

.content{
    flex:1;
    padding:20px;
}

.content h1{
    margin-bottom:20px;
}

/* TOP CARDS */

.cards{
    display:grid;
    grid-template-columns:repeat(auto-fit,minmax(250px,1fr));
    gap:15px;
}

.card{
    background:#fff;
    border-radius:6px;
    padding:20px;
    padding-top:45px;
    position:relative;
    box-shadow:0 2px 5px rgba(0,0,0,.1);
}

.icon-box{
    position:absolute;
    top:-15px;
    left:15px;
    width:60px;
    height:60px;
    border-radius:4px;
    display:flex;
    justify-content:center;
    align-items:center;
}

.card-icon{
    width:28px;
    height:28px;
}

.green{
    background:#4caf50;
}

.orange{
    background:#ff9800;
}

.blue{
    background:#3f51b5;
}

.pink{
    background:#e91e63;
}

/* CHARTS */

.charts{
    margin-top:25px;
    display:grid;
    grid-template-columns:repeat(auto-fit,minmax(300px,1fr));
    gap:15px;
}

.panel{
    background:#fff;
    border-radius:6px;
    padding:15px;
    box-shadow:0 2px 5px rgba(0,0,0,.1);
}

.panel-header{
    height:180px;
    border-radius:4px;
    display:flex;
    justify-content:center;
    align-items:center;
    margin-bottom:15px;
}

.panel-icon{
    width:90%;
    max-height:150px;
    object-fit:contain;
}

/* TABLE */

.tables{
    margin-top:25px;
}

table{
    width:100%;
    border-collapse:collapse;
    background:#fff;
}

th,td{
    border:1px solid #ddd;
    padding:10px;
    text-align:left;
}

/* PROFILE */

.profile{
    display:grid;
    grid-template-columns:1fr 2fr;
    gap:20px;
}

.profile-card{
    background:#fff;
    padding:20px;
    border-radius:6px;
    text-align:center;
}

.avatar{
    width:120px;
    height:120px;
    border-radius:50%;
    object-fit:cover;
    margin-bottom:15px;
}

/* MOBILE */

@media(max-width:800px){
    .layout{
        flex-direction:column;
    }

    .sidebar{
        width:100%;
    }

    .profile{
        grid-template-columns:1fr;
    }
}
.panel h3{
    margin-bottom:8px;
}

.panel p{
    color:#777;
    font-size:13px;
    margin-bottom:5px;
}
.edit-profile{
    padding:0;
}

.panel-title{
    background:#e91e63;
    color:white;
    padding:15px;
}

.panel-title h3{
    margin:0;
}

.panel-title p{
    margin-top:5px;
    color:white;
}

.edit-profile form{
    display:grid;
    grid-template-columns:repeat(3,1fr);
    gap:15px;
    padding:20px;
}

.edit-profile input,
.edit-profile textarea{
    width:100%;
    padding:10px;
    border:none;
    border-bottom:1px solid #ccc;
    background:transparent;
}

.edit-profile textarea{
    grid-column:1/4;
    height:100px;
}

.edit-profile button{
    grid-column:3;
    justify-self:end;
    padding:10px 25px;
    border:none;
    background:#e91e63;
    color:white;
    border-radius:4px;
    cursor:pointer;
}

footer{
    margin-top:20px;
    display:flex;
    justify-content:space-between;
    color:#666;
}

.profile-card{
    background:white;
    padding:30px;
    text-align:center;
    border-radius:6px;
    margin-bottom:20px;
    box-shadow:0 2px 5px rgba(0,0,0,.1);
}

css.basic:
body {
    font-family: Arial, sans-serif;
    line-height: 1.6;
    color: #333;
    margin: 0;
    padding: 0;
}

header, footer {
    background-color: #f4f4f4;
    padding: 20px;
    text-align: center;
}

nav ul {
    list-style: none;
    padding: 0;
    display: flex;
    justify-content: center;
}

nav ul li {
    margin: 0 10px;
}

nav a {
    text-decoration: none;
    color: #333;
}

main {
    padding: 20px;
    max-width: 1200px;
    margin: 0 auto;
}

section {
    margin-bottom: 20px;
}

h1, h2 {
    color: #333;
}

